#!/usr/bin/env python3
"""Background ChatGPT Custom GPT image generator.

Controls Chrome through CDP/Playwright only: no OS mouse movement, no real keyboard,
no UFO clicking. Designed for the user's logged-in Windows Chrome profile.
"""

import argparse
import asyncio
import base64
import json
import os
import re
import shutil
import sys
import time
import urllib.request
from datetime import datetime
from pathlib import Path
from typing import Optional, Tuple

from playwright.async_api import async_playwright, TimeoutError as PlaywrightTimeoutError

GPT_URL = "https://chatgpt.com/g/g-69e8e8cd64fc81918d57af195508f4b1"
DEFAULT_CDP = "http://127.0.0.1:9223"
DEFAULT_OUT_DIR = r"C:\Users\Apinan\Desktop\Work Auto\รูป AiFace" if os.name == "nt" else "/mnt/c/Users/Apinan/Desktop/Work Auto/รูป AiFace"
DEFAULT_RUNTIME_DIR = r"C:\Users\Apinan\Desktop\Work Auto\ufo-aiface\runtime 🏃💨" if os.name == "nt" else "/mnt/c/Users/Apinan/Desktop/Work Auto/ufo-aiface/runtime 🏃💨"
DEFAULT_OLLAMA_URL = "http://127.0.0.1:11434"
DEFAULT_VISION_MODEL = "moondream:latest"
DEFAULT_TEXT_JUDGE_MODEL = "qwen2.5:3b"


def safe_name(text: str, max_len: int = 36) -> str:
    text = re.sub(r"[^0-9A-Za-zก-๙_-]+", "_", text).strip("_")
    return (text[:max_len] or "chatgpt_image")


def reset_runtime_dir() -> Path:
    """Create a trash/runtime workspace and clear old temporary artifacts.

    Final images go to DEFAULT_OUT_DIR only. Screenshots, debug dumps, verify reports,
    rejected candidates, and other temporary files must live under runtime 🏃💨 and be
    deleted at the end so the output folder stays clean.
    """
    runtime_dir = Path(DEFAULT_RUNTIME_DIR)
    if runtime_dir.exists():
        shutil.rmtree(runtime_dir, ignore_errors=True)
    runtime_dir.mkdir(parents=True, exist_ok=True)
    return runtime_dir


def cleanup_runtime_dir(runtime_dir: Optional[Path]):
    if not runtime_dir:
        return
    try:
        if runtime_dir.exists():
            shutil.rmtree(runtime_dir, ignore_errors=True)
    except Exception:
        pass


async def find_or_create_gpt_page(context):
    # Reuse the dedicated GPT tab if present; do NOT bring it to front.
    for pg in context.pages:
        if "chatgpt.com/g/g-699b39eeedc4819180aeb6ad24c464d9" in (pg.url or ""):
            return pg
    # New tab through CDP. This may create a tab, but later actions are DOM/CDP only.
    pg = await context.new_page()
    await pg.goto(GPT_URL, wait_until="domcontentloaded", timeout=60000)
    return pg


async def set_prompt_without_real_keyboard(page, prompt: str):
    # Wait for ChatGPT composer. #prompt-textarea is the verified selector on this machine.
    box = page.locator("#prompt-textarea").last
    await box.wait_for(state="visible", timeout=30000)

    # Pure DOM input: no OS keypress, no mouse movement.
    await box.evaluate(
        """(el, text) => {
            el.focus();
            if (el.tagName === 'TEXTAREA' || el.tagName === 'INPUT') {
                el.value = text;
            } else {
                el.textContent = text;
            }
            el.dispatchEvent(new InputEvent('input', {bubbles: true, inputType: 'insertText', data: text}));
            el.dispatchEvent(new Event('change', {bubbles: true}));
        }""",
        prompt,
    )

    # Prefer ChatGPT send button; fallback to Enter through CDP only (not hardware keyboard).
    send_candidates = [
        "button[data-testid='send-button']",
        "button[aria-label*='Send']",
        "button[aria-label*='ส่ง']",
    ]
    for sel in send_candidates:
        btn = page.locator(sel).last
        try:
            if await btn.count() and await btn.is_enabled(timeout=1500):
                await btn.click(timeout=5000)
                return
        except Exception:
            pass

    await box.press("Enter")


async def collect_large_images(page):
    return await page.evaluate(
        """() => Array.from(document.images).map((img, idx) => ({
            idx,
            src: img.currentSrc || img.src || '',
            alt: img.alt || '',
            w: img.naturalWidth || img.width || 0,
            h: img.naturalHeight || img.height || 0
        })).filter(x => x.src && x.w >= 200 && x.h >= 200)
          .sort((a,b)=>(b.w*b.h)-(a.w*a.h))"""
    )


async def fetch_image_bytes_in_browser(page, url: str):
    return await page.evaluate(
        """async (url) => {
            const r = await fetch(url, { credentials: 'include' });
            const ct = r.headers.get('content-type') || '';
            const ab = await r.arrayBuffer();
            const bytes = new Uint8Array(ab);
            let bin = '';
            const chunk = 0x8000;
            for (let i = 0; i < bytes.length; i += chunk) {
                bin += String.fromCharCode.apply(null, bytes.subarray(i, i + chunk));
            }
            return { ok: r.ok, status: r.status, ct, b64: btoa(bin), size: bytes.length };
        }""",
        url,
    )


def technical_image_gate(res: dict, img: dict, require_full: bool = True) -> Tuple[bool, str]:
    """Reject thumbnails/old previews before any semantic vision check.

    ChatGPT pages may contain 512px jpeg thumbnails, avatars, previous images, or cached
    previews. The final image that is safe to send must be a real estuary image with
    enough resolution/size. This prevents the previous wrong 512x512 JPEG send.
    """
    src = img.get("src", "") or ""
    ct = (res.get("ct") or "").lower()
    size = int(res.get("size") or 0)
    w = int(img.get("w") or 0)
    h = int(img.get("h") or 0)

    if "backend-api/estuary/content" not in src:
        return False, "ไม่ใช่ ChatGPT estuary content URL"
    if not res.get("ok"):
        return False, f"fetch ไม่สำเร็จ status={res.get('status')}"
    if "image" not in ct:
        return False, f"content-type ไม่ใช่รูป: {ct}"
    if require_full:
        # ChatGPT may deliver jpeg or png depending on generation. Do not accept tiny thumbnails.
        if w < 1000 or h < 700:
            return False, f"resolution ต่ำเกินไป/น่าจะ thumbnail: {w}x{h}"
        if size < 300_000:
            return False, f"ไฟล์เล็กเกินไป/น่าจะ preview: {size} bytes"
    else:
        if w < 768 or h < 768:
            return False, f"resolution ต่ำเกินไป: {w}x{h}"
        if size < 120_000:
            return False, f"ไฟล์เล็กเกินไป: {size} bytes"
    return True, "ผ่าน technical gate"


def extract_json_object(text: str) -> dict:
    try:
        return json.loads(text)
    except Exception:
        pass
    m = re.search(r"\{.*\}", text, re.S)
    if not m:
        raise ValueError(f"ไม่มี JSON ใน vision response: {text[:300]}")
    return json.loads(m.group(0))


def ollama_generate(payload: dict, ollama_url: str = DEFAULT_OLLAMA_URL, timeout: int = 90) -> str:
    data = json.dumps(payload).encode("utf-8")
    req = urllib.request.Request(
        ollama_url.rstrip("/") + "/api/generate",
        data=data,
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    with urllib.request.urlopen(req, timeout=timeout) as r:
        raw = r.read().decode("utf-8", "replace")
    return json.loads(raw).get("response", "")


def text_judge_match(prompt: str, caption: str, model: str = DEFAULT_TEXT_JUDGE_MODEL, min_confidence: float = 0.75) -> Tuple[bool, dict]:
    judge_prompt = f"""
You are a strict verifier. Decide whether the IMAGE CAPTION matches the USER REQUEST.

USER REQUEST:
{prompt}

IMAGE CAPTION FROM MOONDREAM:
{caption}

Return ONLY JSON:
{{"matches_prompt":true/false,"confidence":0.0-1.0,"detected_subject":"...","reason":"..."}}

Judge the CORE SUBJECT first. If the caption clearly shows the requested main objects, set matches_prompt=true even if the caption does not literally say words like "3D prop", "low detail", or "smooth". Only set false when the main subject is missing or clearly wrong. Style constraints such as white background/no people/no text should reduce confidence only when clearly violated. For Thai prompts, translate intent: ร้านขายผ้า=cloth/fabric shop or stall, กระท่อมเล็กๆ=small hut/cottage, ผ้าหลากสี=colorful cloth/towels/fabric hanging or folded.
""".strip()
    try:
        text = ollama_generate({
            "model": model,
            "prompt": judge_prompt,
            "stream": False,
            "options": {"temperature": 0},
        }, timeout=90)
        report = extract_json_object(text)
        report["raw_judge_response"] = text
        confidence = float(report.get("confidence") or 0.0)
        ok = bool(report.get("matches_prompt")) and confidence >= min_confidence
        return ok, report
    except Exception as e:
        return False, {"matches_prompt": False, "confidence": 0.0, "detected_subject": "", "reason": f"Text judge error: {e}"}


def moondream_verify_image_b64(
    image_b64: str,
    prompt: str,
    model: str = DEFAULT_VISION_MODEL,
    ollama_url: str = DEFAULT_OLLAMA_URL,
    min_confidence: float = 0.75,
) -> Tuple[bool, dict]:
    """Use local Moondream as the image inspector, then grade the caption.

    Moondream is good at describing images but often ignores strict JSON output.
    Therefore the robust workflow is: Moondream caption -> local text judge -> pass/fail.
    """
    try:
        caption = ollama_generate({
            "model": model,
            "prompt": "Describe this image in detail in English. Do not repeat the user's prompt. Describe only what is visible.",
            "images": [image_b64],
            "stream": False,
            "options": {"temperature": 0},
        }, ollama_url=ollama_url, timeout=90).strip()
        if not caption:
            return False, {"matches_prompt": False, "confidence": 0.0, "detected_subject": "", "reason": "Moondream returned empty caption"}
        ok, report = text_judge_match(prompt, caption, min_confidence=min_confidence)
        report["moondream_caption"] = caption
        report["vision_model"] = model
        report["text_judge_model"] = DEFAULT_TEXT_JUDGE_MODEL
        return ok, report
    except Exception as e:
        return False, {"matches_prompt": False, "confidence": 0.0, "detected_subject": "", "reason": f"Moondream verify error: {e}"}


async def safe_disconnect(browser):
    # Playwright versions differ: Linux has disconnect(), Windows install here may not.
    try:
        fn = getattr(browser, "disconnect", None)
        if fn:
            await fn()
    except Exception:
        pass


async def generate(
    prompt: str,
    output: Optional[str],
    cdp_url: str,
    timeout_sec: int,
    require_full: bool = True,
    vision_model: str = DEFAULT_VISION_MODEL,
    min_confidence: float = 0.75,
):
    out_dir = Path(DEFAULT_OUT_DIR)
    out_dir.mkdir(parents=True, exist_ok=True)
    if output:
        output_path = Path(output)
    else:
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        output_path = out_dir / f"chatgpt_bg_{stamp}_{safe_name(prompt)}.png"

    runtime_dir = reset_runtime_dir()

    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp(cdp_url, timeout=20000)
        context = browser.contexts[0]
        page = await find_or_create_gpt_page(context)
        await page.wait_for_load_state("domcontentloaded", timeout=60000)

        before = {x.get("src") for x in await collect_large_images(page)}
        await set_prompt_without_real_keyboard(page, prompt)

        deadline = time.time() + timeout_sec
        last_seen = []
        while time.time() < deadline:
            await page.wait_for_timeout(2500)
            imgs = await collect_large_images(page)
            last_seen = imgs[:3]
            candidates = [x for x in imgs if x.get("src") and x.get("src") not in before]
            # Prefer ChatGPT estuary image URLs, then largest new image.

⚠️ [... middle content omitted — showing head and tail ...]

                    tech_ok, tech_reason = technical_image_gate(res, img, require_full=require_full)
                    if not tech_ok:
                        print(f"REJECT_TECH {tech_reason} src_w={img.get('w')} src_h={img.get('h')} ct={res.get('ct')} size={res.get('size')}", file=sys.stderr)
                        continue

                    vision_ok, vision_report = await asyncio.to_thread(
                        moondream_verify_image_b64,
                        res["b64"],
                        prompt,
                        vision_model,
                        DEFAULT_OLLAMA_URL,
                        min_confidence,
                    )
                    report_path = runtime_dir / f"{output_path.stem}.verify.json"
                    report_path.write_text(
                        json.dumps({
                            "technical_gate": tech_reason,
                            "image": img,
                            "content_type": res.get("ct"),
                            "size": res.get("size"),
                            "vision_model": vision_model,
                            "min_confidence": min_confidence,
                            "vision_ok": vision_ok,
                            "vision_report": vision_report,
                        }, ensure_ascii=False, indent=2),
                        encoding="utf-8",
                    )
                    if not vision_ok:
                        print(f"REJECT_VISION {vision_report}", file=sys.stderr)
                        try:
                            report_path.unlink(missing_ok=True)
                        except Exception:
                            pass
                        continue

                    output_path.write_bytes(base64.b64decode(res["b64"]))
                    # Reports are detection/debug artifacts; keep the output folder clean.
                    # The user wants only final wanted image outputs in Desktop\\Work Auto\\รูป 3D.
                    cleanup_runtime_dir(runtime_dir)
                    await safe_disconnect(browser)
                    return str(output_path), res, img, vision_report
                except Exception as e:
                    print(f"REJECT_ERROR {e}", file=sys.stderr)
                    continue

        await safe_disconnect(browser)
        cleanup_runtime_dir(runtime_dir)
        raise TimeoutError(f"No downloadable generated image found. Last images: {last_seen}")


async def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("prompt", help="Thai prompt to send to ChatGPT GPT")
    ap.add_argument("--output", "-o", default=None, help="Output PNG path")
    ap.add_argument("--cdp", default=DEFAULT_CDP, help="Chrome CDP endpoint")
    ap.add_argument("--timeout", type=int, default=150, help="Max seconds to wait")
    ap.add_argument("--vision-model", default=DEFAULT_VISION_MODEL, help="Ollama vision model for semantic verification")
    ap.add_argument("--min-confidence", type=float, default=0.75, help="Minimum Moondream confidence before accepting/sending")
    ap.add_argument("--allow-preview", action="store_true", help="Allow lower-res preview images (normally off)")
    args = ap.parse_args()

    path, res, img, vision_report = await generate(
        args.prompt,
        args.output,
        args.cdp,
        args.timeout,
        require_full=not args.allow_preview,
        vision_model=args.vision_model,
        min_confidence=args.min_confidence,
    )
    print(path)
    print(f"content_type={res.get('ct')} size={res.get('size')} source_w={img.get('w')} source_h={img.get('h')}")
    print(f"vision_model={args.vision_model} confidence={vision_report.get('confidence')} subject={vision_report.get('detected_subject')} reason={vision_report.get('reason')}")


if __name__ == "__main__":
    try:
        asyncio.run(main())
    except Exception as e:
        print(f"ERROR: {e}", file=sys.stderr)
        sys.exit(1)
